function saveProfile(p: Profile) {
  if (typeof window === "undefined") return;
  walletSetItem("orderlyProfile", JSON.stringify(p));
}

function hasGraduatedProfile(p: Profile | null): boolean {
  const brokerId = p?.brokerId?.trim().toLowerCase();
  return p?.graduated === true || Boolean(brokerId && brokerId !== "demo");
}

function isValidBrokerId(id: string): boolean {
  return /^[a-z0-9_-]{5,15}$/.test(id) && !isReservedBrokerId(id);
}

function isReservedBrokerId(id: string): boolean {
  return /orderly|order/i.test(id);
}

function getBrokerIdErrorKey(
  id: string
): "graduation.brokerIdError" | "graduation.brokerIdReservedError" | null {
  if (isReservedBrokerId(id)) return "graduation.brokerIdReservedError";
  if (!/^[a-z0-9_-]{5,15}$/.test(id)) return "graduation.brokerIdError";
  return null;
}

function validateFee(value: string, min: number, max: number): string {
  const num = parseFloat(value);
  if (value === "" || Number.isNaN(num)) return "Enter a valid number";
  if (num < min || num > max) return `Valid range: ${min} – ${max} bps`;
  if (Math.round(num * 10) !== num * 10)
    return "Max precision: 0.1 bps increments";
  return "";
}

function getTierForStakedOrder(totalStakedOrder: number): Tier {
  if (totalStakedOrder >= 7_000_000) return "Diamond";
  if (totalStakedOrder >= 2_000_000) return "Platinum";
  if (totalStakedOrder >= 250_000) return "Gold";
  if (totalStakedOrder >= 100_000) return "Silver";
  return "Public";
}

async function fetchWalletStakedOrder(address: string): Promise<number> {
  const payload = await orderlyApi<StakingBalanceResponse>({
    endpoint: `/v1/staking/balance${buildQueryString({ address })}`,
    token: null,
  });

  if (payload.success === false)
    throw new Error("Failed to load staking balance.");
  const totalStakedOrder = Number(payload.data?.total_staked_order ?? 0);
  return Number.isFinite(totalStakedOrder) ? totalStakedOrder : 0;
}

function getPaymentChainConfig(chainId: PaymentChainId) {
  return (
    SUPPORTED_CHAINS.find(chain => chain.id === chainId) ?? SUPPORTED_CHAINS[1]
  );
}

function getPaymentChainId(chainId: PaymentChainId): number {
  const chain = getPaymentChainConfig(chainId);
  return getOrderlyEnvConfig().env === "prod" ? chain.chainId : chain.testnetId;
}

function getPaymentApiChainId(chainId: PaymentChainId): PaymentApiChainId {
  const chain = getPaymentChainConfig(chainId);
  return getOrderlyEnvConfig().env === "prod" ? chain.id : chain.testnetApiId;
}

function getPaymentTokenAddress(
  chainId: PaymentChainId,
  token: PaymentToken
): string {
  return TOKEN_ADDRESSES[getPaymentApiChainId(chainId)]?.[token] || "";
}

function createPaymentSelection(
  token: PaymentToken,
  chainId: PaymentChainId
): PaymentSelection {
  return {
    token,
    chainId,
    apiChainId: getPaymentApiChainId(chainId),
    numericChainId: getPaymentChainId(chainId),
    tokenAddress: getPaymentTokenAddress(chainId, token),
  };
}

function paymentSelectionMatches(
  option: PaymentOption,
  selection: PaymentSelection
) {
  return (
    option.token === selection.token && option.chainId === selection.chainId
  );
}

function paymentSelectionFromOption(option: PaymentOption): PaymentSelection {
  return {
    token: option.token,
    chainId: option.chainId,
    apiChainId: option.apiChainId,
    numericChainId: option.numericChainId,
    tokenAddress: option.tokenAddress,
  };
}

function paymentContextFromOption(
  option: PaymentOption
): PaymentExecutionContext | null {
  if (!option.feeOption) return null;
  return {
    token: option.token,
    chainId: option.chainId,
    apiChainId: option.apiChainId,
    numericChainId: option.numericChainId,
    tokenAddress: option.tokenAddress,
    feeOption: option.feeOption,
    tokenDecimals: option.tokenDecimals,
  };
}

function getPaymentBalanceKey(token: PaymentToken, chainId: PaymentChainId) {
  return `${token}:${chainId}`;
}

function getContractResult(value: unknown) {
  if (value && typeof value === "object" && "status" in value) {
    const item = value as { status?: unknown; result?: unknown };
    return item.status === "success" ? item.result : undefined;
  }
  return value;
}

function getFeeOption(
  feeOptions: DexCreatorGraduationFeeOptions | null,
  token: PaymentToken
): DexCreatorGraduationFeeOption | null {
  if (!feeOptions) return null;
  if (token === "USDC") return feeOptions.usdc;
  if (token === "USDT") return feeOptions.usdt;
  return feeOptions.order;
}

function formatPaymentDisplay(
  option: DexCreatorGraduationFeeOption | null,
  token: PaymentToken
): string {
  if (!option) return `Loading ${token}`;
  if (token === "ORDER") {
    const amount = option.amount.toLocaleString(undefined, {
      maximumFractionDigits: 2,
    });
    const usdValue = option.currentPrice
      ? ` (~$${(option.amount * option.currentPrice).toFixed(2)})`
      : "";
    return `${amount} ORDER${usdValue}`;
  }
  return `${option.amount.toLocaleString(undefined, { maximumFractionDigits: 2 })} ${token}`;
}

function parseFeeValue(value: string): number {
  const fee = Number(value);
  return Number.isFinite(fee) ? fee : 0;
}

