  const [brokerIdAvailable, setBrokerIdAvailable] = useState<boolean | null>(
    null
  );
  const [brokerIdChecking, setBrokerIdChecking] = useState(false);
  const brokerIdCheckTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [walletAddress, setWalletAddress] = useState<string>("");
  const [stakingPreview, setStakingPreview] = useState<{
    totalStakedOrder: number;
    tier: Tier;
  } | null>(null);
