function PaymentOptionSelector({
  options,
  selected,
  onSelect,
}: {
  options: PaymentOption[];
  selected: PaymentOption;
  onSelect: (opt: PaymentOption) => void;
}) {
  const [open, setOpen] = useState(false);

  return (
    <>
      <button
        type="button"
        onClick={() => setOpen(true)}
        className="flex w-full items-center justify-between rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) px-4 py-3 text-left transition-colors hover:bg-(--bg-hover)"
      >
        <div className="flex items-center gap-3">
          <TokenLogo token={selected.token} />
          <div className="flex flex-col gap-0.5">
            <span className="text-sm font-semibold text-(--fg-primary)">
              {selected.feeDisplay}
            </span>
            <span className="flex items-center gap-1 text-xs text-(--fg-secondary)">
              <NetworkLogo
                network={selected.chainId}
                className="text-(--fg-secondary)"
              />
              {selected.chainName}
            </span>
            <span
              className={`text-xs ${selected.isSufficient ? "text-(--fg-secondary)" : "text-[#FF6390]"}`}
            >
              Your balance:{" "}
              {selected.balanceLoading
                ? "Loading..."
                : selected.balance === undefined
                  ? "--"
                  : formatNumberFixed(selected.balance, 2)}{" "}
              {selected.token}
            </span>
          </div>
        </div>
        <span className="text-sm font-medium text-(--fg-brand)">Change</span>
      </button>

      <Modal
        open={open}
        onClose={() => setOpen(false)}
        title="Select payment option"
      >
        <div className="flex flex-col gap-2">
          {options.map(opt => (
            <button
              key={`${opt.token}-${opt.chainId}`}
              type="button"
              onClick={() => {
                onSelect(opt);
                setOpen(false);
              }}
              className={`flex w-full items-center justify-between rounded-xl border px-4 py-3 text-left transition-colors ${
                selected.token === opt.token && selected.chainId === opt.chainId
                  ? "border-(--line-brand) bg-[rgba(188,135,255,0.08)]"
                  : "border-(--line-subtle) bg-(--bg-surface-secondary) hover:bg-(--bg-hover)"
              }`}
            >
              <div className="flex items-center gap-3">
                <TokenLogo token={opt.token} />
                <div className="flex flex-col">
                  <span className="text-sm font-medium text-(--fg-primary)">
                    {opt.token}
                  </span>
                  <span className="flex items-center gap-1 text-xs text-(--fg-secondary)">
                    <NetworkLogo network={opt.chainId} />
                    {opt.chainName}
                  </span>
                </div>
              </div>
              <div className="flex flex-col items-end gap-0.5">
                <span className="text-sm font-medium text-(--fg-primary)">
                  {opt.feeDisplay}
                </span>
                <span
                  className={`text-xs ${opt.isSufficient ? "text-(--fg-secondary)" : "text-[#FF6390]"}`}
                >
                  Balance:{" "}
                  {opt.balanceLoading
                    ? "Loading..."
                    : opt.balance === undefined
                      ? "--"
                      : formatNumberFixed(opt.balance, 2)}{" "}
                  {opt.token}
                </span>
              </div>
            </button>
          ))}
        </div>
      </Modal>
    </>
  );
}

function FeeCard({
  label,
  value,
  onChange,
  error,
  hint,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  error?: string;
  hint: string;
}) {
  const handleBlur = () => {
    const num = parseFloat(value);
    if (!Number.isNaN(num)) {
      const rounded = Math.round(num * 10) / 10;
      if (rounded !== num) {
        onChange(String(rounded));
      }
    }
  };

  return (
    <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
      <div className="mb-2 text-sm font-medium text-(--fg-primary)">
        {label}
      </div>
      <div
        className={`flex items-center rounded-lg border bg-(--bg-input) px-3 py-2 ${error ? "border-(--fg-negative)" : "border-(--line-subtle)"}`}
      >
        <input
          type="text"
          inputMode="decimal"
          value={value}
          onChange={e => onChange(e.target.value)}
          onBlur={handleBlur}
          className="w-full bg-transparent text-sm font-medium text-(--fg-primary) outline-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
        />
        <span className="text-xs text-(--fg-secondary)">bps</span>
      </div>
      <p
        className={`mt-1 text-[11px] ${error ? "text-(--fg-negative)" : "text-(--fg-secondary)"}`}
      >
        {error || hint}
      </p>
    </div>
  );
}
